<template><div class="page"><h2 class="title">能效分析</h2><div class="toolbar"><select v-model="dg" @change="load" class="sel"><option v-for="g in groups" :key="g" :value="g">{{g}}</option></select></div><div class="section"><div ref="chart" style="height:360px"></div></div></div></template><script setup>import { ref,onMounted,nextTick } from 'vue';import * as e from 'echarts';import { useEnergyStore } from '../store/energy'
const store=useEnergyStore(), groups=ref([]), dg=ref(''), chart=ref(null)
async function load(){ const d=await store.fetchJSONRaw(`/api/efficiency/trend?device_group=${dg.value}&days=7`)||{}; await nextTick(); const ch=e.init(chart.value); ch.setOption({tooltip:{trigger:'axis'},legend:{data:['平均功率','最大功率','能效%']},xAxis:{type:'category',data:(d.trend||[]).map(x=>x.date)},yAxis:[{type:'value',name:'kW'},{type:'value',name:'%'}],series:[{name:'平均功率',type:'line',data:(d.trend||[]).map(x=>x.avg_power_kw),smooth:true},{name:'最大功率',type:'line',data:(d.trend||[]).map(x=>x.max_power_kw),smooth:true,lineStyle:{type:'dashed'}},{name:'能效%',type:'line',yAxisIndex:1,data:(d.trend||[]).map(x=>x.efficiency_pct),smooth:true,lineStyle:{color:'#00a870'}}]}) }
async function init(){ const w=await store.fetchJSONRaw('/api/device/workcenters'); if(w?.flat){ groups.value=w.flat.filter(n=>n.code?.startsWith('WC-')).map(n=>n.name); if(groups.value.length){ dg.value=groups.value[0]; load() } } }
onMounted(init)
</script><style scoped>.page{display:flex;flex-direction:column;gap:16px}.title{font-size:18px;color:#333}.toolbar{display:flex;gap:10px;background:#fff;padding:12px 16px;border-radius:10px;border:1px solid #e8eaed}.sel{padding:6px 10px;border:1px solid #ddd;border-radius:6px}.section{background:#fff;border:1px solid #e8eaed;border-radius:10px;padding:20px}</style>